// Minimal Bootstrap-like behavior for navbar collapse (lightweight stub)
(function(){
  document.addEventListener('click', function(e){
    var t = e.target;
    if(!t) return;
    // handle navbar-toggle
    if(t.classList && t.classList.contains('navbar-toggle')){
      var container = t.closest('.navbar');
      if(!container) return;
      var collapse = container.querySelector('.navbar-collapse');
      if(!collapse) return;
      collapse.classList.toggle('in');
      // simple aria toggle
      var expanded = collapse.classList.contains('in');
      collapse.setAttribute('aria-expanded', expanded);
    }
  });
})();
